from fastapi import FastAPI
from fastapi.responses import JSONResponse

app = FastAPI()

@app.get("/checkpoints/{checkpoint_id}")
async def get_checkpoint(checkpoint_id: str):
    r = _checkpoints.get(checkpoint_id)
    if not r:
        return JSONResponse({"error": "not found"}, status_code=404)
    return JSONResponse({
        "checkpoint_id":      r.checkpoint_id,
        "segment":            r.segment,
        "step_count":         r.step_count,
        "progress_summary":   r.progress_summary,
        "recent_tool_calls":  r.tool_calls_summary[-5:],  # show last 5
        "decision":           r.decision,
    })

@app.post("/checkpoints/{checkpoint_id}/continue")
async def continue_checkpoint(checkpoint_id: str):
    r = _checkpoints.get(checkpoint_id)
    if not r or r.decision is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    r.decision = CheckpointDecision.CONTINUE
    r.event.set()
    return JSONResponse({"status": "approved"})

@app.post("/checkpoints/{checkpoint_id}/redirect")
async def redirect_checkpoint(checkpoint_id: str, message: str):
    r = _checkpoints.get(checkpoint_id)
    if not r or r.decision is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    r.decision = CheckpointDecision.REDIRECT
    r.redirect_msg = message
    r.event.set()
    return JSONResponse({"status": "redirect injected"})

@app.post("/checkpoints/{checkpoint_id}/abort")
async def abort_checkpoint(checkpoint_id: str):
    r = _checkpoints.get(checkpoint_id)
    if not r or r.decision is not None:
        return JSONResponse({"error": "not found or already decided"}, status_code=400)
    r.decision = CheckpointDecision.ABORT
    r.event.set()
    return JSONResponse({"status": "aborted"})
